effect.shader:
void main() {

    vec2 tileSize = vec2(size)/acLayerSize;
    vec2 adjPhase = vec2(-phase.x,phase.y);

    if( acPass==0 ) {

        vec2 st = acLayerNorm.st;
        vec2 texelSize = 1.0 / acLayerSize.xy;

        st -= vec2(.5,.5);
        st.x -= mod(st.x+adjPhase.x/acLayerSize.x, tileSize.x);
        st += vec2(.5,.5);
        //st.x += tileSize.x / 2.;

        float blur = (tileSize.x/texelSize.x)/2.;
        int nSamples = int(clamp(blur, 1.01, 100.01));

        vec4 outColor = texture2DCv(inputImg.texture, (vec4(st,0.,1.)*acLayerToScreen).st);
        for(int i=1; i<nSamples; i++ ) {
            vec2 offset = vec2(tileSize.x,0.) * (float(i) / float(nSamples - 1) - 0.5);
            outColor += texture2DCv(inputImg.texture, (vec4(st-offset,0.,1.)*acLayerToScreen).st);
        }
        gl_FragColor = outColor/float(nSamples);

    } else {

        vec2 st = acLayerNorm.st;
        vec2 texelSize = 1.0 / acLayerSize.xy;

        st -= vec2(.5,.5);
        st.y -= mod(st.y+adjPhase.y/acLayerSize.y, tileSize.y);
        st += vec2(.5,.5);
        //st.y += tileSize.y / 2.;

        float blur = tileSize.y/texelSize.y;
        int nSamples = int(clamp(blur, 1.01, 100.01));

        vec4 outColor = texture2DCv(inputImg.texture, (vec4(st,0.,1.)*acLayerToScreen).st);
        for(int i=1; i<nSamples; i++ ) {
            vec2 offset = vec2(0.,tileSize.y) * (float(i) / float(nSamples - 1) - 0.5);
            outColor += texture2DCv(hblur.texture, (vec4(st-offset,0.,1.)*acLayerToScreen).st);
        }
        gl_FragColor = outColor/float(nSamples);

    }
}
